window.PRUEBA = {"id": "historia", "titulo": "ECEP 2024 · Educación Básica · Historia y Geografía", "preguntas": [{"n": 1, "textoBase": "En el siguiente gráfico se visualiza la distribución de la Población Económicamente Activa (PEA) según sector económico en los países de América Latina. La distribución porcentual de esta población permite evaluar un patrón geográfico para estos países: PEA según sector económico. (CEPAL, Estadísticas e Indicadores)", "enunciado": "Según el gráfico presentado, ¿cuál es este patrón geográfico?", "alternativas": ["La importancia del sector Servicios especialmente en los países del Cono Sur y México, y la importancia del sector Agrícola en América Andina y Centroamérica.", "La proyección de la población económicamente activa en el sector Industria, independiente del país latinoamericano.", "La transformación que se observa hacia el sector Servicios de los países centroamericanos mientras disminuye el aporte del sector Agricultura.", "La continuidad de la dependencia de recursos naturales que se observa en los países del Cono Sur de América Latina."], "correcta": "A", "visual": true, "pagina": 4, "imagen": "/imagenes/ecep/pruebas/historia/p04.png"}, {"n": 2, "textoBase": "Lea la siguiente definición: “Los agentes morfogenéticos son los elementos del medio natural que son capaces de generar diferentes modelados sobre la superficie terrestre a través de la incorporación de energía cinética. (…) El agua del planeta es el principal agente morfogenético.” (Instituto de Geografía, Universidad Católica de Chile)", "enunciado": "¿Qué materiales transportan y depositan estos agentes morfogenéticos?", "alternativas": ["Sedimentos como arena, grava y arcilla, contribuyendo a la formación de depósitos aluviales y estructuras sedimentarias.", "Rocas y minerales, preservando las formaciones geológicas sin alterar el paisaje.", "Partículas finas y polvo, desgastando la superficie rocosa sin generar sedimentación.", "Formaciones rocosas compactas, contribuyendo a la generación de estructuras de gran tamaño en zonas boscosas."], "correcta": "A"}, {"n": 3, "textoBase": "El Informe Desigualdad Regional en Chile (PNUD, 2018) concluye que “durante la última década todas las regiones han mejorado en la mayoría de los indicadores […]. No obstante, junto a estos avances los datos revelan importantes brechas interregionales en indicadores más complejos”, tales como salud, salarios y oferta educativa.", "enunciado": "A partir de esta conclusión, ¿cómo se pueden disminuir las desigualdades interregionales en Chile?", "alternativas": ["Combinando los indicadores básicos con políticas territorialmente focalizadas en indicadores más complejos.", "Atendiendo prioritariamente los indicadores complejos del desarrollo como salarios, acceso y cobertura educacional en algunas regiones.", "Combinando la disminución de las brechas interregionales con un aumento de la oferta educativa en el nivel terciario en todas las regiones.", "Atendiendo prioritariamente los indicadores básicos del desarrollo como pobreza, ingresos y esperanza de vida en todas las regiones."], "correcta": "A"}, {"n": 4, "textoBase": "En general, los ríos de Chile tienen un régimen dominantemente nival en la Zona Central y Norte, y régimen mixto nival y pluvial en la Zona Sur. De acuerdo con las estimaciones de cambio climático, en la cordillera de Los Andes se espera que la isoterma de 0 °C suba entre 300 y 500 metros, reduciendo la capacidad de la cordillera de almacenar nieve, aun cuando la precipitación no varíe.", "enunciado": "Según esta información, ¿en qué zonas naturales de Chile es esperable que el cambio climático produzca el mayor estrés hídrico?", "alternativas": ["Norte Grande, Norte Chico y Zona Central.", "Norte Chico, Zona Central y Zona Austral.", "Norte Chico, Zona Central y Zona Sur.", "Norte Chico, Zona Sur y Zona Austral."], "correcta": "C"}, {"n": 5, "textoBase": "Un docente desarrolla la unidad Sociedad y territorio: la región en Chile y América. En una clase, cuyo objetivo es que los estudiantes comprendan el concepto de región geográfica, utiliza como recurso pedagógico los siguientes mapas (Köppen climate types in Chile, Adam Peterson, www.educarchile.cl).", "enunciado": "¿Cuál de los siguientes criterios para definir una región es factible aplicar a través del anterior recurso pedagógico?", "alternativas": ["La escala de los fenómenos geográficos.", "Las relaciones medio-hábitat humano.", "La presencia de patrones espaciales.", "Las divisiones político-administrativas."], "correcta": "A", "visual": true, "pagina": 7, "imagen": "/imagenes/ecep/pruebas/historia/p07.png"}, {"n": 6, "textoBase": "Con el objetivo de que las y los estudiantes distingan las causas del proceso de independencia desde una perspectiva multicausal, el docente les pide que en un grupo completen un cuadro sobre las causas de la independencia. Al monitorear la actividad, se da cuenta de que uno de ellos respondió lo siguiente: La acefalía monárquica. El ansia de mayor participación de los criollos. La corrupción de los gobernadores americanos.", "enunciado": "¿Qué problema para el logro del objetivo de la actividad se advierte en la respuesta de este estudiante?", "alternativas": ["La limitación del análisis a un tipo de causalidad.", "La falta de diacronía en la secuencia de las causas.", "La inexistente distinción entre condiciones y motivaciones.", "La ausencia de perspectivas historiográficas en el reconocimiento de las causas."], "correcta": "A"}, {"n": 7, "textoBase": "Una docente, en la unidad Formación de la sociedad americana y de los principales rasgos de Chile colonial, evaluará el nivel de comprensión de sus estudiantes respecto de las relaciones fronterizas en el siglo XVIII, considerando las formas de convivencia entre españoles y los mapuche.", "enunciado": "¿Cuál de las siguientes actividades podría emplear la docente para evaluar el aprendizaje adquirido?", "alternativas": ["Los estudiantes construyen una ficha descriptiva sobre la guerra defensiva establecida por los españoles y la respuesta de los mapuche.", "Los estudiantes explican la esclavitud decretada por los españoles que afectó a la población indígena en situaciones bélicas y su impacto a partir de la lectura de una fuente.", "Los estudiantes discuten sobre los efectos a corto y largo plazo de las estrategias de negociación sobre el comercio con los mapuche establecidas por los españoles.", "Los estudiantes confeccionan una infografía que aborde la política española de fundaciones fuertes y ciudades hacia el sur del Biobío y su destrucción por parte de los mapuche."], "correcta": "C"}, {"n": 8, "enunciado": "La zona natural de Chile, denominada Norte Grande, involucra las regiones de Arica y Parinacota, Tarapacá, Antofagasta y la mitad norte de Atacama. ¿Cuál es una característica común de estas regiones?", "alternativas": ["El altiplano andino.", "El desierto minero.", "Los valles cordilleranos.", "Los valles costeros."], "correcta": "B"}, {"n": 9, "textoBase": "El saldo migratorio es la diferencia entre la inmigración y la emigración. El siguiente gráfico del INE 2018 proyecta el saldo migratorio de Chile desde 1996 hasta el año 2050 (INE, Estimaciones y proyecciones de la población de Chile 1992-2050).", "enunciado": "De acuerdo con el gráfico presentado, ¿qué situación se proyecta para la población?", "alternativas": ["Un saldo migratorio positivo y estable en el tiempo.", "Un incremento exponencial de la emigración en Chile.", "Una estabilización del saldo migratorio en el tiempo.", "Una disminución progresiva de la inmigración en Chile."], "correcta": "C", "visual": true, "pagina": 10, "imagen": "/imagenes/ecep/pruebas/historia/p10.png"}, {"n": 10, "textoBase": "Lea el siguiente texto: “El partido conservador […] se fue constituyendo en torno a ciertos principios como “armonizar las formas republicanas y democráticas de la institucionalidad política con la doctrina católica” principio atravesado transversalmente por el de orden. Los conservadores buscaban mantener el orden imperante, respecto de la relación entre la Iglesia y el Estado, mostrándose reticentes a que la Iglesia se sometiera a la voluntad del poder civil, situación que los llevó a mantener una sostenida lucha contra el laicismo […]. Respecto del campo político, los conservadores no lo fueron tanto, contrariamente a sus predecesores, los pelucones, ya que desde un comienzo “fueron absolutamente contrarios al autoritarismo portaliano y entusiastas partidarios de disminuir las facultades del ejecutivo […], orientaron su acción hacia la defensa de las garantías constitucionales, y estaban convencidos de que sin libertad de prensa de asociación y de sufragio, no existía posibilidad de sobrevivir…”. (BCN, 2023)", "enunciado": "Considerando la descripción anterior del partido conservador, ¿qué creencia era compartida entre este sector y el de los liberales chilenos en el siglo XIX?", "alternativas": ["La defensa de la autoridad fuerte del presidente de la república.", "La mantención del poder de la Iglesia católica sobre el Estado.", "El respeto a la legalidad y a los derechos políticos de los ciudadanos.", "La lucha contra el patronato que amenazaba con someter al Estado a la Iglesia."], "correcta": "C"}, {"n": 11, "textoBase": "En su Boletín sobre Demografía de 2020, las Naciones Unidas informan que: Se espera que la población mundial aumente en dos mil millones de personas, de los 7.700 millones actuales a 9.700 millones en 2050, antes de alcanzar un máximo de casi 11.000 millones a finales de siglo, a medida que siga disminuyendo la tasa de fecundidad. Durante este período, se prevé que la población mundial será cada vez más urbana y que la población de 65 años o más superará en número a la de menores de 5 años. Se prevé que, de aquí a 2050, la mitad del crecimiento de la población mundial se originará en solo 9 países, a saber: India, Nigeria, Pakistán, República Democrática del Congo, Etiopía, Tanzania, Indonesia, Egipto y los Estados Unidos de América (en orden decreciente). (Naciones Unidas, 2023)", "enunciado": "A partir del extracto anterior, ¿qué medida será urgente tomar para mitigar los efectos del crecimiento de población a nivel global?", "alternativas": ["Disminuir la presión social inmigrante de los países, sobre todo en aquellos en los que tienen la mitad del crecimiento de la población mundial.", "Aumentar la tasa de fecundidad a nivel mundial, sobre todo porque está en peligro el recambio generacional al haber pocos nacimientos.", "Aumentar el ritmo de crecimiento de población después del año 2050, en un contexto donde será fundamental incentivar los movimientos migratorios.", "Disminuir la presión sobre recursos y servicios de los países, en un contexto de aumento de la población mayor en un mundo altamente urbanizado."], "correcta": "D"}, {"n": 12, "textoBase": "Lea el siguiente texto: “Hace aproximadamente 12.000 años, durante el Neolítico, el surgimiento de la agricultura revolucionó la historia, […] permitió a la humanidad introducir cambios tan trascendentales como el sedentarismo y la formación de poblaciones que han marcado por completo el desarrollo de nuestra historia”. (Crespo, C., 2022, National Geographic)", "enunciado": "Según la información anterior, ¿cuál de las siguientes opciones expresa correctamente el impacto que permitió el desarrollo de la agricultura?", "alternativas": ["El decrecimiento de comunidades nómades.", "El auge del mercado laboral orientado a la explotación de la tierra.", "El decrecimiento de comunidades sedentarias.", "El auge del mercado alimenticio orientado a la venta de productos."], "correcta": "A"}, {"n": 13, "textoBase": "El río Nilo tuvo gran importancia para los antiguos egipcios, quienes lo adoraban como a una divinidad. En efecto, el historiador griego Heródoto llamó a Egipto “un regalo del Nilo”.", "enunciado": "Considerando lo anterior, ¿qué permitió el Nilo para Egipto?", "alternativas": ["El despliegue de la urbanización, siendo un eje político y social.", "El establecimiento de los límites naturales para evitar ser invadidos.", "El desarrollo de la agricultura en su territorio y alrededores.", "El intercambio comercial producto de la llegada de inmigrantes."], "correcta": "C"}, {"n": 14, "textoBase": "La separación entre la Iglesia y el Estado ha sido un proceso que se desarrolló en distintos momentos históricos, marcando una ruptura importante en la relación entre el poder religioso y el poder político.", "enunciado": "¿En qué movimiento filosófico-cultural, caracterizado por su énfasis en el uso de la razón y la crítica a las instituciones tradicionales, se consolidó la idea de la separación entre la Iglesia y el Estado?", "alternativas": ["Renacimiento, donde el retorno a los valores clásicos reavivó el interés por el humanismo y las ciencias, pero mantuvo la influencia de la Iglesia en la política.", "Absolutismo, en el cual los monarcas consolidaron el poder centralizado, pero dependían de la legitimación de la Iglesia para sostener su autoridad.", "Humanismo, que enfatizó la dignidad y el valor del ser humano, imponiendo una separación clara entre Iglesia y Estado.", "Ilustración, en la que se promovió el uso de la razón y la autonomía política, sentando las bases para la separación entre la Iglesia y el Estado."], "correcta": "D"}, {"n": 15, "textoBase": "Un profesor en el desarrollo de la unidad: Las civilizaciones de la antigüedad aborda el siguiente objetivo de clase: “Relacionar las principales características institucionales de Roma con su extensión territorial”.", "enunciado": "¿Cuál de los siguientes recursos didácticos es apropiado para abordar este aprendizaje con los estudiantes?", "alternativas": ["Un mapa donde se muestren los territorios que abarca el extenso Imperio romano.", "Un testimonio de cómo eran las campañas militares de extensión territorial de los romanos.", "Una fuente en que se explique la organización burocrática del Imperio romano y sus distintas provincias.", "Un fragmento que dé cuenta de la vinculación social existente entre la ciudad de Roma y los habitantes de las provincias."], "correcta": "C"}, {"n": 16, "textoBase": "Los pueblos indígenas se extendían a lo largo del territorio nacional/chileno de forma independiente; por ejemplo, en el norte se ubicaban a lo largo de la costa, dedicándose preferentemente a la pesca y la recolección.", "enunciado": "¿A qué cultura originaria se refiere el ejemplo anterior?", "alternativas": ["Atacameña.", "Aymara.", "Changa.", "Chona."], "correcta": "C"}, {"n": 17, "textoBase": "El Imperio Inca fue uno de los más extensos en la América precolombina y su territorio se conoció como Tahuantinsuyu. A su período de dominio se le conoció como incanato, el cual concluyó con la toma de Cuzco por parte de los conquistadores españoles.", "enunciado": "¿Cuál fue la extensión del Imperio Inca hacia el sur por el Océano Pacífico?", "alternativas": ["Hasta la ciudad del Cuzco - Perú.", "Hasta la zona de Tacna - Perú.", "Hasta el desierto de Atacama - Chile.", "Hasta el río Maule - Chile."], "correcta": "D"}, {"n": 18, "textoBase": "Lea los siguientes textos sobre el proceso de organización de las expediciones a América:\nFuente A: “La tarea de ocupar las nuevas tierras no fue una actividad organizada por el Estado, salvo por excepción. Por lo general, el rey no incurría en gastos y dejaba entregada la organización y realización a capitanes de conquistas, que se comprometían a correr con su financiamiento, reunir soldados, naves y en lograr éxito con ella… el Estado señalaba el territorio y delegaba en el capitán algunos atributos. Las diversas estipulaciones entre el Estado y el jefe conquistador quedaron consagradas mediante un contrato o capitulación”. (Villalobos, S., 1980)\nFuente B: “Las cosas suplicadas es que Vuestras Altezas dan y otorgan a don Cristóbal de Colón, son las que se siguen: [...] Ítem que de todas y cualesquiera mercadurías, sean perlas, piedras preciosas, oro, plata, especiería, y otras cualesquiera cosas y mercadurías de cualquiera especie, nombre y manera que sean, que se compraren, trocaren, hallaren, ganaren y hubieren dentro en los límites de dicho Almirantazgo, que desde ahora Vuestras Altezas hacen merced al dicho don Cristóbal [...]”. (Capitulaciones de Santa Fe, 17 de abril de 1492)", "enunciado": "Al contrastar las fuentes, ¿qué afirmación explica la organización de las empresas de conquista?", "alternativas": ["Todas las empresas de conquista deben tener firmada una capitulación, así como también el financiamiento del Estado en cada una de ellas.", "La excepción a las empresas de conquista, que fueron en su mayoría privadas, estuvo representada en la empresa colombina, dado el fuerte financiamiento del Estado.", "El jefe conquistador, sea en la empresa privada o en la empresa colombina, debe reunir todos los fondos para solventar los gastos de la travesía.", "La mayor motivación de ambas empresas de conquista es la expansión de la fe cristiana, así como también el servicio a Dios y al Rey."], "correcta": "B"}, {"n": 19, "textoBase": "Observe la siguiente representación cartográfica (UCE, 2023, Paralelos y Meridianos, Currículum Nacional).", "enunciado": "¿Cuál es el significado de los grados que acompañan a las líneas imaginarias trazadas en la imagen anterior?", "alternativas": ["La distancia angular que lo separa del paralelo del Ecuador.", "El grado de inclinación del eje terrestre.", "El recorrido espacial que se trata desde el meridiano de Greenwich.", "El número de paralelos que falta por recorrer para llegar a los polos."], "correcta": "A", "visual": true, "pagina": 17, "imagen": "/imagenes/ecep/pruebas/historia/p17.png"}, {"n": 20, "textoBase": "Lea el siguiente extracto de una fuente secundaria que aborda el rol de José Miguel Carrera durante el proceso de emancipación: “Pensamos que detrás de Carrera no existe un programa propiamente tal, por lo menos mientras busca afianzar su poder. El lenguaje republicano-liberal de Carrera es un expediente legitimador moderno para justificar una nueva y moderna forma de hacer política: la personalidad caudillesca. […] Carrera no fue un revolucionario: más bien hizo uso de un lenguaje revolucionario. Su manejo incluso fue altamente manipulador; en ningún momento, por ejemplo, intentó asegurar la completa independencia de Chile, aun cuando su régimen fue el que más se acercó a ella”. (Jocelyn-Holt, A., 2023)", "enunciado": "De acuerdo con la fuente, ¿qué visión de Carrera tiene Jocelyn-Holt?", "alternativas": ["El de un prócer que promovió la independencia, mediante el uso de conceptos asociados al liberalismo.", "El de un caudillo militar que empleó un discurso republicano y liberal, pero no promovió la emancipación.", "El de un caudillo revolucionario y rupturista, que supo emplear el lenguaje de la revolución.", "El de un prócer que legitimó su movimiento, usando el lenguaje propio de la revolución."], "correcta": "D"}, {"n": 21, "textoBase": "Lea el siguiente fragmento sobre el proceso de emancipación: “Dueños efectivos del poder desde días atrás, afirma, por la influencia que ejercían sin contrapeso sobre el conde de la Conquista, y dueños también de la fuerza pública por haberse ganado a su causa a los militares que tenían el mando de las tropas y de las milicias, los patriotas pensaban revestir con toda la solemnidad posible los actos que iban a verificarse ese día”. (Barros Arana, D., 2002)", "enunciado": "¿A qué grupo dentro de la sociedad hispánica se está aludiendo en la fuente anterior?", "alternativas": ["A los latifundistas.", "A los criollos.", "A los realistas.", "A los caudillos militares."], "correcta": "B"}, {"n": 22, "textoBase": "Lea el siguiente fragmento de una carta de Diego Portales: “¡Para qué carajo sirven las constituciones y papeles, si son incapaces de poner remedio a un mal que se sabe existe!... En Chile la ley no sirve para otra cosa que no sea producir la anarquía ... el libertinaje, el pleito eterno... ¡Maldita ley entonces si no deja al brazo del Gobierno proceder libremente en el momento oportuno! […]” (Portales, D., 1834, Carta a Antonio Garfias)", "enunciado": "De acuerdo con la fuente, ¿qué expresa Diego Portales sobre el ideario político del contexto en que se ubica?", "alternativas": ["Se expresa hastiado del período de ensayos constitucionales, por la falta de una autoridad central que imponga orden.", "Manifiesta su desprecio al constitucionalismo, en un momento en que existe una hegemonía conservadora en el país.", "Expresa su adherencia a gobiernos fuertes y centralizados, así como también al ideario conservador.", "Manifiesta una crítica de la constitución anterior a la de 1833 y a la inutilidad de las normas constitucionales."], "correcta": "B"}, {"n": 23, "textoBase": "Lea la siguiente fuente: “Disfrutamos de un régimen político que no imita las leyes de los vecinos; más que imitadores de otros, en efecto, nosotros mismos servimos de modelo para algunos […]; respecto a las leyes, todos gozan de iguales derechos en la defensa de sus intereses particulares; en lo relativo a los honores, cualquiera que se distinga en algún aspecto puede acceder a los cargos públicos, pues se lo elige más por sus méritos que por su categoría social; y tampoco al que es pobre, por su parte, su oscura posición le impide prestar sus servicios a la patria, si es que tiene la posibilidad de hacerlo. Tenemos por norma respetar la libertad, tanto en los asuntos públicos como en las rivalidades diarias de unos con otros […]. Si bien en los asuntos privados somos indulgentes, en los públicos, en cambio, ante todo por un respetuoso temor, jamás obramos ilegalmente, sino que obedecemos a quienes les toca el turno de mandar, y acatamos las leyes…”. (El discurso fúnebre de Pericles)", "enunciado": "¿Qué afirmación contenida en la fuente anterior corresponde a una característica distintiva del sistema democrático ateniense?", "alternativas": ["“Si bien en los asuntos privados somos indulgentes, en los públicos, en cambio, ante todo por un respetuoso temor, jamás obramos ilegalmente…”.", "“Disfrutamos de un régimen político que no limita las leyes de los vecinos”.", "“… obedecemos a quienes les toca el turno de mandar, y acatamos las leyes…”.", "“… cualquiera que se distinga en algún aspecto puede acceder a los cargos públicos…”."], "correcta": "D"}, {"n": 24, "textoBase": "El desarrollo de la economía chilena, durante la segunda mitad del siglo XIX, está relacionada con la conformación territorial.", "enunciado": "¿Cuál de las siguientes afirmaciones explicita dicha relación?", "alternativas": ["Solo la riqueza asociada a la minería del Norte Chico y las exportaciones agrícolas asociadas a la fiebre del oro constituyeron el motor fundamental de la economía durante todo el siglo.", "Con la guerra del salitre y la chilenización de la Araucanía, la expansión capitalista estuvo marcada por la presencia de capitales extranjeros.", "Con el desarrollo de una modernización económica asociada a la guerra del salitre, la incorporación de maquinaria a vapor y las relaciones económicas capitalistas se dinamizó la economía nacional.", "La guerra contra la Confederación Perú Boliviana y la guerra del Pacífico aportaron al país grandes riquezas mineras."], "correcta": "B"}, {"n": 25, "textoBase": "Desde la Declaración de Independencia –en el siglo XIX– hasta el presente, Chile se ha caracterizado por un sistema presidencialista.", "enunciado": "¿Cuál de las siguientes afirmaciones describe el sistema presidencial a través de la historia de la república?", "alternativas": ["La separación de las funciones del jefe de Estado y del jefe de gobierno y un ejecutivo sujeto a la mayoría del congreso, de acuerdo con la constitución presidencial de 1925.", "Un sistema político presente en las constituciones, con un poder ejecutivo y legislativo con atribuciones y facultades equitativas.", "Un sistema político propio de una república democrática, en donde el presidente de la república hace uso ilimitado de las facultades extraordinarias, según las constituciones de 1833, 1925 y 1980.", "La unificación de la jefatura de Estado y la de gobierno en la figura del presidente de la república, quien tiene la facultad de aplicar el estado de sitio según la constitución de 1833 y 1925."], "correcta": "D"}, {"n": 26, "textoBase": "En 1935 las mujeres votaron por primera vez en Chile, en las elecciones municipales. Recién en 1949 se promulgó el sufragio universal femenino, posibilitando su participación en las elecciones presidenciales y parlamentarias de 1952.", "enunciado": "Respecto del sufragio femenino, ¿qué presión posibilitó de manera progresiva este derecho?", "alternativas": ["La presión de las organizaciones feministas, particularmente a través de campañas públicas.", "La presión que ejercieron unas pocas mujeres, como Elena Caffarena, que se enfrentó a la resistencia masculina.", "La presión que realizaron organizaciones campesinas en alianza con las mujeres de los espacios urbanos, particularmente las universitarias.", "La presión internacional, especialmente de la Organización Mundial de la Salud, por democratizar la participación."], "correcta": "A"}, {"n": 27, "textoBase": "Observe los siguientes climogramas (Educar Chile, 2023, Climogramas Chillán- Gral. Bernardo O’Higgins y Concepción- Carriel Sur, Currículum Nacional).", "enunciado": "¿Qué factor climático permite explicar las diferencias térmicas registradas entre ambas estaciones climatológicas?", "alternativas": ["El tipo de relieve en que se emplaza.", "La diferencia altitudinal que presentan.", "La proximidad respecto de una masa oceánica.", "El grado de influencia del anticiclón del Pacífico."], "correcta": "C", "visual": true, "pagina": 24, "imagen": "/imagenes/ecep/pruebas/historia/p24.png"}, {"n": 28, "textoBase": "En la trayectoria hacia la recuperación de la democracia en Chile, durante la primera mitad de la década de 1980, hubo un hito clave que llevó a la ciudadanía a expresar su descontento en las calles y a debilitar la base política de la dictadura de Augusto Pinochet.", "enunciado": "¿A cuál de las siguientes situaciones corresponde este hito?", "alternativas": ["Al rechazo a una guerra con Argentina en 1981.", "A los efectos de la crisis económica de 1982.", "Al asesinato de Eduardo Frei Montalva en 1982.", "A la extensión de la dictadura con la Constitución de 1980."], "correcta": "B"}, {"n": 29, "textoBase": "Lea atentamente los siguientes extractos de textos:\n“A fines del siglo XVIII encontramos que el salariado minero [...] no posee una comprensión de su ubicación y de las relaciones que ellos deben tener en el sistema social, […] su desarrollo en términos de comprensión social no estaba avanzado a fines del siglo XVIII”. (Carmagnani, M., 1963)\n“Durante las dos décadas que enmarcaron el tránsito del siglo XIX al XX, el norte salitrero chileno asistió a la formación definitiva, en los niveles discursivo, organizacional y político, de una clase obrera”. (Pinto, J., 2004)", "enunciado": "Al comparar los textos proporcionados, ¿cómo se refleja la transformación de la clase trabajadora desde el periodo Colonial hasta el Republicano en términos de estructura social y comprensión de su posición en la sociedad?", "alternativas": ["A través del desarrollo de una identidad de clase más definida y estructurada.", "Mediante la implementación y evolución de leyes sociales que regulan el trabajo.", "Por la modernización de las estructuras políticas y económicas que impactan en la organización laboral.", "Por la transformación y reestructuración de la organización del trabajo en el contexto económico de cada periodo."], "correcta": "A"}, {"n": 30, "textoBase": "Existen diversas teorías que explican el poblamiento americano. Solo una de ellas es autóctona, mientras que las restantes son todas alóctonas y plantean que América fue poblada desde fuera de ella.", "enunciado": "Considerando esta información, ¿cuáles son los aspectos comunes que poseen las teorías alóctonas?", "alternativas": ["Que están comprendidas temporalmente entre los años 10000 y el 5000 a.C.", "Que la dirección del poblamiento fue desde el hemisferio norte hacia el sur.", "Que las rutas de los migrantes, antes de arribar a América, fueron de oeste a este.", "Que la matriz de los grupos humanos que emigró a América es de origen asiático."], "correcta": "C"}, {"n": 31, "textoBase": "Tiempo cronológico y tiempo histórico son dos elementos que forman parte esencial de la enseñanza del pensamiento histórico en la escuela, pues permiten que los estudiantes se sitúen en la dimensión temporal del pasado. No obstante, ambos son conceptos diferentes.", "enunciado": "¿En cuál de las siguientes opciones se está aludiendo principalmente al tiempo cronológico?", "alternativas": ["Los ciclos económicos que han ocurrido en la historia.", "Las transformaciones ocurridas en una década de la historia.", "Los acontecimientos ocurridos antes o después de un hito histórico.", "Los diferentes acontecimientos producidos en el mismo tiempo en lugares distintos."], "correcta": "C"}, {"n": 32, "textoBase": "El feudalismo fue un sistema político, económico y social que se desarrolló durante la Alta Edad Media y dominó Europa Occidental entre los siglos XI al XII.", "enunciado": "¿Cuál de las siguientes es una característica de este sistema?", "alternativas": ["La centralidad de la agricultura y la autarquía económica y política.", "El poder de la Iglesia católica y el crecimiento de las ciudades.", "Las Cruzadas en el afán de recuperar la ruta de las especias y controlar su tránsito.", "Los dominios centralizados de los señores y una creciente apertura económica."], "correcta": "A"}, {"n": 33, "textoBase": "El uso de la razón fue un elemento importante dentro de las características del pensamiento ilustrado, especialmente en el cuestionamiento a las ideas que sustentaban a las instituciones que se mantenían desde la Edad Media.", "enunciado": "De acuerdo con este contexto, ¿qué institución disminuye su poder por la influencia de las ideas ilustradas?", "alternativas": ["La familia, ya que conservaba una estructura jerarquizada y basada en el mayorazgo.", "El legislativo, ya que conservaba una estructura heredada desde el Imperio Romano.", "El Rey, ya que conservaba el poder político apoyando a la emergente clase burguesa.", "La Iglesia, ya que conservaba el poder político influenciando en los gobernantes."], "correcta": "D"}, {"n": 34, "textoBase": "Lea el siguiente texto: A Fines de los años 1540 cierta devoción mariana se había desarrollado en una humilde capilla al norte de la Ciudad de México en el lugar mismo en que antaño se levantaba un santuario dedicado a Toci, la diosa madre. Aquella devoción […] había conocido el fervor de los indios que seguían llevando a la virgen española ofrendas que antaño destinaban a la diosa […] agregando el temor [de los españoles] de ver que los indígenas siguieron adorando con el nombre de Toci a la antigua madre de los dioses y no a la virgen María. (Gruzinski, Serge)", "enunciado": "¿Qué concepto describe la situación señalada en el texto anterior?", "alternativas": ["Aculturación.", "Sincretismo.", "Transculturación.", "Evangelización."], "correcta": "B"}, {"n": 35, "enunciado": "¿Cuál de las siguientes opciones contiene una característica de la administración colonial impuesta por España a América?", "alternativas": ["La interdependencia entre la Iglesia y la Corona en el nombramiento de funcionarios.", "La prohibición de los criollos de acceder a cargos públicos.", "La centralización del poder a través de las instituciones con asiento en España y América.", "La fragmentación de los poderes del Estado en distintas instituciones."], "correcta": "C"}, {"n": 36, "textoBase": "El monocultivo es una práctica agrícola muy utilizada por las ventajas económicas derivadas de su implementación. Sin embargo, acarrea una serie de daños para el medio ambiente.", "enunciado": "¿Cuál es una consecuencia ambiental negativa de corto plazo para el área de emplazamiento de los monocultivos?", "alternativas": ["Degradación de suelos.", "Pérdida de biodiversidad.", "Alteración del ciclo hidrológico.", "Aceleración del efecto invernadero."], "correcta": "B"}, {"n": 37, "textoBase": "Observe la siguiente línea de tiempo:", "enunciado": "¿Qué componente del tiempo histórico está explícito en la línea del tiempo anterior?", "alternativas": ["Los ritmos del devenir histórico.", "La duración de los procesos históricos.", "La simultaneidad de los hechos históricos.", "Los elementos de cambio y continuidad de los procesos históricos."], "correcta": "B", "visual": true, "pagina": 30, "imagen": "/imagenes/ecep/pruebas/historia/p30.png"}, {"n": 38, "textoBase": "Lea el siguiente texto: “Los ciudadanos son iguales ante la Ley, las leyes son conocidas públicamente, universales, estables, no retroactivas (salvo excepciones), y aplicadas de manera justa y consistente a todos (y todas) los ciudadanos por un poder judicial independiente”. (Biblioteca del Congreso Nacional, Guía de Formación Cívica)", "enunciado": "¿Qué concepto se define en la idea anterior?", "alternativas": ["Estado de Derecho.", "Estado.", "Soberanía.", "Ciudadanía."], "correcta": "A"}, {"n": 39, "textoBase": "Según la Constitución, el presidente de la república cuenta con una variedad de atribuciones, tanto en materia de gobierno y administración, como en las labores legislativas, judiciales y económicas.", "enunciado": "¿Cuál es una de las atribuciones legislativas del presidente?", "alternativas": ["Cuidar de las recaudaciones de renta.", "Ejercer la potestad reglamentaria.", "Otorgar indultos.", "Convocar a plebiscito."], "correcta": "B"}, {"n": 40, "textoBase": "Entre 1823 y 1829 hubo tres Constituciones que fracasaron, lo que da cuenta de visiones sobre la institucionalidad política que quiso implementarse en Chile. Una de ellas fue la de 1828.", "enunciado": "¿Cuál es un planteamiento de esta Constitución que da cuenta de su carácter liberal?", "alternativas": ["La creación del cargo de presidente de la república.", "La finalización de la esclavitud en todo el territorio nacional.", "La protección de la vida privada de las personas ante los abusos del Estado.", "La necesidad de establecer leyes que regulen el comportamiento de las personas."], "correcta": "C"}, {"n": 41, "enunciado": "¿Cuál de las siguientes afirmaciones explica la función del Ministerio Público de Chile?", "alternativas": ["Garantizar que todas las personas cuenten con un abogado defensor.", "Elaborar informes sobre la situación nacional en temas de Derechos Humanos.", "Dirigir la investigación de los delitos cometidos y ejercer la acción penal pública.", "Velar porque exista un debido proceso y tramitar las apelaciones."], "correcta": "C"}, {"n": 42, "textoBase": "Durante el siglo XXI, la democracia es el sistema imperante en la mayor parte de los países del mundo. Estos países tienen en común diferentes problemáticas, las que han surgido también en nuestro país.", "enunciado": "¿Cuál es la principal problemática de las democracias participativas actuales?", "alternativas": ["La desigualdad ciudadana.", "La falta de transparencia del Estado.", "La desafección política.", "La creación del unipartidismo."], "correcta": "C"}, {"n": 43, "textoBase": "Estudiantes de un quinto básico, deben investigar acerca de las democracias existentes en el siglo XXI en diferentes países del mundo. Para ello, la docente les solicita buscar diversas fuentes primarias y secundarias con el propósito de compararlas con el ordenamiento democrático existente en nuestro país.", "enunciado": "¿Qué dimensión del pensamiento histórico pretende promover la docente con este ejercicio?", "alternativas": ["Significación histórica.", "Uso de la evidencia.", "Causa y efecto.", "Perspectiva histórica."], "correcta": "B"}, {"n": 44, "textoBase": "En un sexto básico, la docente realiza una actividad en que les propone a sus estudiantes que piensen en políticas públicas a largo plazo (20 a 30 años). Para ello, utiliza la siguiente gráfica del INE (2018), que proyecta la población al año 2050 según grandes grupos de edad (INE, Estimaciones y proyecciones de la población de Chile 1992-2050).", "enunciado": "De acuerdo con el gráfico presentado, ¿qué política pública es adecuada según la proyección?", "alternativas": ["Incrementar las políticas de migración, ya que la gráfica indica que disminuye la población en edad de trabajar.", "Incrementar las políticas dirigidas a la integración de los adultos mayores, ya que la gráfica indica un aumento de este grupo de población.", "Incrementar las políticas de natalidad para mantener estable la población, ya que la gráfica indica una disminución de los menores de edad.", "Mantener las políticas actuales, ya que la gráfica indica que los grupos de edades se estabilizarán en el tiempo."], "correcta": "B", "visual": true, "pagina": 34, "imagen": "/imagenes/ecep/pruebas/historia/p34.png"}, {"n": 45, "textoBase": "Durante el desarrollo de una clase, un estudiante señala que el Renacimiento constituyó un movimiento intelectual que rescató los valores clásicos del mundo griego, lo que propició el desarrollo del antropocentrismo.", "enunciado": "De acuerdo con lo expresado por el estudiante, ¿qué aspectos deben ser mejorados para consolidar este saber?", "alternativas": ["El surgimiento del mercantilismo como eje motor de las transformaciones sociales.", "La existencia de corrientes diversas que permiten cuestionar el concepto desde la perspectiva de la religión.", "La relevancia del humanismo que permite el desarrollo del razonamiento en el centro de las artes y las ciencias.", "La creación de las perspectivas protestantes para la consolidación del mundo moderno."], "correcta": "C"}, {"n": 46, "textoBase": "Lea el siguiente texto: “Ahora se crea una primera unidad del mundo: las técnicas circulan velozmente; los productos y los tipos de alimentación se difunden; la cocina española, el trigo, el carnero, los bovinos se introducen a América; a más o menos largo plazo, el maíz, la patata, el chocolate, los pavos llegan a Europa”. (Romano, R. y Tenenti, A., 1989)", "enunciado": "¿Para qué objetivo de clase se puede utilizar la fuente anterior?", "alternativas": ["Conocer la balanza comercial existente durante la Edad Media, comparándola con la actualidad.", "Identificar aquellos productos que tenían más demanda en la época moderna, en relación con la contemporánea.", "Caracterizar la economía mercantilista del siglo XVI, estableciendo relaciones de continuidad y cambio con el presente.", "Analizar los elementos de continuidad y cambio en relación con los procesos de alimentación de la población americana."], "correcta": "C"}, {"n": 47, "textoBase": "Una docente está preparando una actividad de aprendizaje en el marco del Objetivo de Aprendizaje: Comparar la sociedad medieval y moderna, considerando los cambios que implicó la ruptura de la unidad religiosa en Europa, así como el impacto de la imprenta en la difusión del conocimiento y las ideas.", "enunciado": "¿Qué estrategia de aprendizaje puede implementar la docente para atender el objetivo anterior promoviendo la participación activa y reflexiva de las y los estudiantes?", "alternativas": ["Organizar un debate sobre la influencia de la imprenta en la difusión del conocimiento, donde los y las estudiantes argumenten sobre los efectos de esta tecnología en el desarrollo de la modernidad.", "Elaborar una línea de tiempo interactiva, donde los y las estudiantes identifiquen los principales eventos que marcaron la transición de la Edad Media a la modernidad, destacando el papel de la imprenta y los cambios religiosos.", "Realizar una lectura guiada de textos históricos clave sobre la Reforma Protestante, seguida de una discusión para que los y las estudiantes analicen las implicaciones religiosas, sociales y culturales.", "Proponer una investigación grupal sobre las diferencias entre la sociedad medieval y la moderna, enfocándose en el impacto de la ruptura religiosa y su influencia en el desarrollo político y social."], "correcta": "A"}, {"n": 48, "textoBase": "Un docente de sexto básico tiene como objetivo de clases desarrollar el pensamiento histórico de sus estudiantes a partir del estudio del proceso de la Independencia de Chile.", "enunciado": "¿Qué temáticas deberían contener los recursos didácticos que debe emplear el docente?", "alternativas": ["La importancia del proceso, las fuentes para su estudio, los elementos de continuidad y cambio presentes, una mirada en perspectiva del proceso y su dimensión ética.", "Los hechos más importantes acaecidos con su respectiva fechación, los personajes que tuvieron mayor importancia y las consecuencias continentales de lo acontecido.", "Las causas que dieron inicio al proceso, las dificultades enfrentadas y las razones de estas, los conceptos involucrados y las reacciones del imperio español.", "La situación vivida con motivo del aprisionamiento del Rey, la identificación de los líderes del movimiento y sus acciones, y las acciones realizadas por las otras gobernaciones."], "correcta": "D"}, {"n": 49, "textoBase": "Una de las principales dificultades que debe enfrentar un docente de Historia es la existencia de sesgos de todo tipo por parte de las y los estudiantes al momento de enfrentar el estudio de una temática determinada.", "enunciado": "¿Qué estrategia concreta es adecuada ante una situación como esta en clases?", "alternativas": ["Realizar una encuesta para conocerlos en profundidad.", "Respetar la libertad de pensar del o la estudiante.", "Identificar al estudiante para luego hablar en privado con él o ella.", "Solicitar una investigación sobre los argumentos utilizados sobre el tema."], "correcta": "D"}, {"n": 50, "textoBase": "Lea la siguiente fuente: Augusto ganó la voluntad de los soldados con donativos, la del pueblo con la abundancia de alimentos y la de todos con la dulzura de la paz. Su poder fue creciendo insensiblemente al atribuirse los poderes del Senado, de los magistrados y de los comicios, sin que nadie le contradijese. Los más valerosos ciudadanos, y los otros nobles cayendo en, que cuanto más pronto se mostraban a la servidumbre tanto más rápido llegaban las riquezas y los honores; viéndose engrandecidos por este medio, quisieron más el Estado presente seguro, que el pasado peligroso. Ni a las mismas provincias fue desagradable esta forma de Estado, sospechosas del gobierno del Senado, de las disputas de los poderosos y de la avaricia [ambición] de los magistrados. (Suetonio, Vidas de los doce Césares)", "enunciado": "Según esta fuente sobre el imperio romano, ¿qué característica política distinguió el periodo de la República de la época del Imperio?", "alternativas": ["La participación restringida de la población.", "La admisión de ciudadanía a los habitantes de los territorios conquistados.", "La distribución de funciones entre otras autoridades.", "La descentralización de la administración en favor de las provincias."], "correcta": "C"}, {"n": 51, "textoBase": "Lea el siguiente texto: Homenaje y fidelidad en el siglo XII. En primer lugar, cumplieron los homenajes de la manera siguiente: el conde pidió (al futuro vasallo) si deseaba convertirse sin reservas en su hombre, y este respondió: “así lo quiero”. Luego sus manos unidas a las del conde que las estrechó se aliaron mediante un beso. En segundo lugar, aquel que rindió un homenaje comprometió su fe en estos términos: “prometo por mí ser fiel, a partir de este instante, al conde Guillermo, y guardarle ante todos y totalmente mi homenaje de buena fe y malicia”. En tercer lugar, juró sobre la reliquia de los santos. Enseguida, con la vara que tenía en la mano, el conde les dio la investidura a todos aquellos que mediante este pacto le habían prometido seguridad, hecho homenajes y prestado juramento. (Poblete, O., 1962)", "enunciado": "¿Qué rasgo característico de la estructura social feudal está descrito en el texto anterior?", "alternativas": ["La estructura autárquica de la sociedad.", "La sacralización de las relaciones sociales.", "La organización estamental de la sociedad.", "La dependencia económica entre estamentos."], "correcta": "B"}, {"n": 52, "textoBase": "Lea el siguiente texto: Tras su derrota en la guerra de Nueva Granada, el rey árabe Boabdil entrega las llaves de la ciudad a los reyes católicos, Isabel I de Castilla y Fernando II de Aragón, el 2 de enero de 1492.", "enunciado": "¿Cuál es la característica más importante del estado moderno constituido en España en el siglo XV que evidencia este hecho?", "alternativas": ["El proceso de descentralización del poder político.", "La vinculación del poder religioso con la autoridad civil.", "El fortalecimiento del Estado a través de la adquisición de colonias.", "La concentración del poder en la figura de los reyes por derecho divino."], "correcta": "B"}, {"n": 53, "textoBase": "Para el siguiente Objetivo de Aprendizaje: Caracterizar el Imperio Inca, y analizar los factores que posibilitaron la dominación y unidad del Imperio (por ejemplo, red de caminos y sistema de comunicaciones, sistemas de cultivo, organización social, administración, ejército, mita y yanaconaje, sometimiento de pueblos y lengua oficial, entre otros).", "enunciado": "¿Qué conocimientos previos se deben considerar al construir una secuencia de aprendizaje?", "alternativas": ["Las relaciones entre el ser humano y el medio.", "La centralización del poder de un gobernante.", "Los procesos de exploración y conquista de América.", "El impacto de una red comercial en Mesoamérica."], "correcta": "A"}, {"n": 54, "textoBase": "Lea el siguiente texto: El renovado conocimiento filosófico de Aristóteles, de Platón y de los neoplatónicos, así como el de algunos otros pensadores antiguos, y las cada vez más frecuentes traducciones latinas de obras griegas, crearon un clima intelectual extremadamente distinto al de la época precedente. En el periodo medieval no faltaba una gran libertad de pensamiento, pero […] los contendientes en cada debate filosófico varían esencialmente, según el modo en que se pretendía fundar o interpretar la fe y el dogma. La especulación no tenía valor por sí misma, porque estaba ya aceptada la convicción de poseer una verdad superior y divina. (Romano, R. & Tenenti, A., 1972)", "enunciado": "¿Qué elemento del pensamiento moderno está presente en el texto anterior?", "alternativas": ["La exaltación del conocimiento empírico.", "La existencia de la libertad de pensamiento.", "La posibilidad de cuestionar la verdad y el conocimiento.", "El cuestionamiento de la fe y la existencia de un orden divino."], "correcta": "C"}, {"n": 55, "textoBase": "Para el desarrollo de una actividad en que las y los estudiantes deben explicar algunos factores que permitieron el surgimiento de monarquías absolutistas en la Edad Moderna, ¿qué conocimientos previos se deben considerar?", "enunciado": "Para el desarrollo de una actividad en que las y los estudiantes deben explicar algunos factores que permitieron el surgimiento de monarquías absolutistas en la Edad Moderna, ¿qué conocimientos previos se deben considerar?", "alternativas": ["El rol del Renacimiento.", "Las características del quattrocento.", "La burocracia administrativa.", "Los movimientos de órdenes mendicantes."], "correcta": "C"}, {"n": 56, "textoBase": "Una docente, utilizando una estrategia de evaluación formativa, pregunta: “¿Qué adelantos tecnológicos se presentaron en el siglo XIV y cómo estos permitieron perfeccionar la navegación que condujo a los viajes de exploración europeos?” Uno de sus estudiantes responde: “Entre los adelantos podemos encontrar la brújula, el astrolabio, los galeones y los portulanos, los que ayudaron para poder ubicarse de mejor manera y navegar de mejor forma para iniciar los viajes.”", "enunciado": "¿Qué error comete el estudiante en su respuesta?", "alternativas": ["Se confunde al integrar los galeones en su enumeración, ya que su desarrollo corresponde al siglo XVI.", "Se confunde al mencionar que los portulanos se desarrollaron antes del siglo XIV, por lo que no corresponde al periodo señalado.", "Se equivoca al considerar los portulanos como útiles para la navegación surgidos en el siglo XIV, porque ya se usaban anteriormente.", "Se equivoca al considerar el astrolabio, que ya se utilizaba antes del siglo XIV y no es posterior al periodo señalado."], "correcta": "A"}, {"n": 57, "textoBase": "Se tiene el siguiente indicador de evaluación: Explican la relevancia de la Declaración Universal de los Derechos Humanos para el resguardo de las personas y la sociedad.", "enunciado": "¿Qué desempeño da cuenta del indicador señalado?", "alternativas": ["Caracterizan los componentes de la declaración de los Derechos Humanos.", "Establecen las implicancias de la aplicación de los Derechos Humanos luego de la Segunda Guerra Mundial.", "Describen las causas que generaron la declaración de los Derechos Humanos.", "Comparan la declaración de los Derechos Humanos y la del hombre y el ciudadano."], "correcta": "B"}, {"n": 58, "enunciado": "¿Qué actividad de aprendizaje es pertinente para que los y las estudiantes evalúen los problemas de conexión y de aislamiento de Chile?", "alternativas": ["Comparar las redes de transporte y comunicaciones del valle central con las regiones extremas.", "Caracterizar la cobertura de acceso a internet a lo largo de Chile.", "Identificar la densidad poblacional de Chile a lo largo del territorio nacional.", "Definir las estructuras de las redes de conexión de transporte terrestre a lo largo de Chile."], "correcta": "A"}, {"n": 59, "textoBase": "Se tiene el siguiente Objetivo de Aprendizaje: Aplicar el concepto de desarrollo para caracterizar regiones de Chile, considerando: Índice de Desarrollo Humano, Diversidad Productiva y Desarrollo Sustentable.", "enunciado": "¿Qué desempeño da cuenta del cumplimiento del objetivo señalado?", "alternativas": ["Caracterizan, a partir de datos de salud, educación y riqueza, el desarrollo y las implicancias para la sustentabilidad.", "Describen los tipos de desarrollo humano, los procesos económicos y la sustentabilidad ambiental.", "Definen el desarrollo humano, sistema económico y sustentabilidad.", "Mencionan situaciones que representan el concepto de desarrollo humano aplicado y medioambiental."], "correcta": "A"}, {"n": 60, "textoBase": "Durante una evaluación formativa, una docente pregunta: “¿A qué coyuntura histórica se le atribuye el inicio de la Edad Media?”. Un estudiante responde: “A la invasión de los musulmanes de Valí”.", "enunciado": "¿Qué práctica pedagógica puede implementar la docente para retroalimentar formativamente esta respuesta?", "alternativas": ["Pedir al estudiante que investigue otras posibles causas históricas del inicio de la Edad Media y compare su relevancia.", "Sugerir al estudiante que revise sus notas y vuelva a responder, dando pistas sobre el evento clave de la caída del Imperio Romano.", "Ofrecer una explicación sobre la cronología de los eventos que llevaron a la Edad Media, destacando el papel de la caída del Imperio Romano de Occidente.", "Facilitar una actividad grupal donde los estudiantes analicen las causas del inicio de la Edad Media para fomentar el trabajo colaborativo y la corrección de errores."], "correcta": "C"}]};
